B.Mn=s(["Dual Modes: Generate both Individual KHQR (personal accounts) and Merchant KHQR (business accounts).","Multi-Currency Support: Full handling of USD and KHR currencies.","Auto-Configuration: No setup required for Android & iOS. Clean, promise-based wrapper provided for Web.","Type-Safe: Clean models for parameters and response structures."],t.s)
B.Rg=new A.bq(B.mc,["package_1","flutter_bakong_payway","A production-ready plugin to generate Bakong KHQR payment codes (Individual and Merchant) in Flutter. Wraps the national standard Bakong KHQR SDK for mobile platforms and integrates JavaScript SDK bindings for Flutter Web, offering a seamless API for cross-platform Cambodian payments.","https://pub.dev/packages/flutter_bakong_payway","https://github.com/VengAnn/flutter_bakong_payway_sdk","1.0.1",B.Nh,B.Mn,"import 'package:flutter_bakong_payway/flutter_bakong_payway.dart';\n\nfinal bakong = FlutterBakongPayway();\n\n// Generate Individual QR Code\nfinal info = IndividualInfo(\n  accountId: 'your_account@bank',\n  merchantName: 'John Doe',\n  currency: KHQRCurrency.usd,\n  amount: 10.00,\n);\n\nfinal result = await bakong.generateIndividualQR(info);\nprint('KHQR String: ${result?.qr}'); // Standardized KHQR string"],t.R)
