B.OY=s(["Fully Automatic CLI Setup: Run one command to set up iOS (App Groups, ShareExtension) and Android without opening native IDEs.","Rich Content Handling: Seamlessly shares and receives text, images, videos, audio, documents, and archives (40+ file types supported).","Hot & Cold Starts: Captures shared intents whether the app is running in the background or launched from a closed state.","Self-App Filtering: Automatically excludes your own app from showing up in the OS sharesheet when trigger-sharing."],t.s)
B.Ri=new A.bq(B.mc,["package_3","share_intent_package","A zero-configuration, two-way share intent handler for iOS and Android. Makes it extremely easy to receive shared content from other apps and share outgoing content. Includes an automated CLI utility that generates all complex platform configurations\u2014like App Groups, Share Extensions, and Android Intent Filters.","https://pub.dev/packages/share_intent_package","https://github.com/vengann/share_intent_package","1.0.0",B.Ng,B.OY,"import 'package:share_intent_package/share_intent_package.dart';\n\n// 1. Listen for incoming shares (Hot & Cold starts)\nvoid initShareListener() async {\n  // Cold start shared content\n  final initialContent = await ShareIntentPackage.instance.getInitialSharing();\n  \n  // Hot start stream\n  ShareIntentPackage.instance.getMediaStream().listen((content) {\n    print(\"Received shared files: ${content.filePaths}\");\n  });\n}\n\n// 2. Share outgoing content\nawait ShareIntentPackage.shareFiles(['/path/to/my_image.png']);"],t.R)
